import{_ as e,o as n,c as t,a0 as s}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Which Plan Applies to You","description":"","frontmatter":{},"headers":[],"relativePath":"subscriptions/effective-plan.md","filePath":"subscriptions/effective-plan.md"}'),i={name:"subscriptions/effective-plan.md"};function o(r,a,l,p,c,h){return n(),t("div",null,[...a[0]||(a[0]=[s(`<h1 id="which-plan-applies-to-you" tabindex="-1">Which Plan Applies to You <a class="header-anchor" href="#which-plan-applies-to-you" aria-label="Permalink to &quot;Which Plan Applies to You&quot;">​</a></h1><p>A plan can reach you from more than one direction, so the app has to decide which one actually counts. The winner is your <strong><a href="./../getting-started/glossary.html#effective-plan">effective plan</a></strong> — the one your limits and features come from right now. Your usage panel shows it, along with a <strong>plan source</strong> label telling you <em>where</em> it came from.</p><h2 id="the-one-rule-to-remember" tabindex="-1">The one rule to remember <a class="header-anchor" href="#the-one-rule-to-remember" aria-label="Permalink to &quot;The one rule to remember&quot;">​</a></h2><blockquote><p><strong>Premium does not flow downhill automatically.</strong> An alliance does <strong>not</strong> become premium just because its kingdom is premium. For an alliance to get the kingdom&#39;s premium, the King must <strong>offer</strong> a <a href="./../getting-started/glossary.html#grant">grant</a> and the alliance must <strong>accept</strong> it. Without that explicit offer-and-accept, the alliance stays on its own plan (or the free tier).</p></blockquote><p>There is no silent &quot;inherited&quot; plan. If your alliance isn&#39;t premium, having a premium kingdom above you changes nothing until a grant is accepted.</p><h2 id="how-the-app-picks-—-for-an-alliance" tabindex="-1">How the app picks — for an alliance <a class="header-anchor" href="#how-the-app-picks-—-for-an-alliance" aria-label="Permalink to &quot;How the app picks — for an alliance&quot;">​</a></h2><p>The app checks these in order and stops at the first one that applies:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ALLIANCE — which plan wins?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  1. Direct alliance plan            ──▶  panel shows:  &quot;Direct alliance plan&quot;</span></span>
<span class="line"><span>        (the alliance has its own subscription)</span></span>
<span class="line"><span>        │  none?</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>  2. Accepted kingdom grant          ──▶  panel shows:  &quot;Accepted kingdom grant&quot;</span></span>
<span class="line"><span>        (the King offered the kingdom plan AND the alliance accepted)</span></span>
<span class="line"><span>        │  none?</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>  3. Free tier                       ──▶  panel shows:  &quot;Free tier&quot;</span></span>
<span class="line"><span>        (the automatic fallback)</span></span></code></pre></div><p>Note what is <strong>not</strong> in that list: there is no step where an alliance quietly picks up its kingdom&#39;s plan on its own. A kingdom grant only counts once it has been <strong>accepted</strong> — a pending, rejected, revoked, or expired offer does nothing.</p><h2 id="how-the-app-picks-—-for-a-kingdom" tabindex="-1">How the app picks — for a kingdom <a class="header-anchor" href="#how-the-app-picks-—-for-a-kingdom" aria-label="Permalink to &quot;How the app picks — for a kingdom&quot;">​</a></h2><p>A kingdom is simpler, because grants are something a kingdom <em>gives</em>, not receives:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>KINGDOM — which plan wins?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  1. Direct kingdom plan             ──▶  panel shows:  &quot;Direct kingdom plan&quot;</span></span>
<span class="line"><span>        (the kingdom has its own subscription)</span></span>
<span class="line"><span>        │  none?</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>  2. Free tier                       ──▶  panel shows:  &quot;Free tier&quot;</span></span>
<span class="line"><span>        (the automatic fallback)</span></span></code></pre></div><h2 id="reading-the-plan-source-label" tabindex="-1">Reading the plan source label <a class="header-anchor" href="#reading-the-plan-source-label" aria-label="Permalink to &quot;Reading the plan source label&quot;">​</a></h2><p>The <strong>plan source</strong> label on your usage panel tells you exactly which tier you landed on:</p><table tabindex="0"><thead><tr><th>Label you see</th><th>What it means</th></tr></thead><tbody><tr><td><strong>Direct alliance plan</strong></td><td>This alliance has its own subscription.</td></tr><tr><td><strong>Accepted kingdom grant</strong></td><td>Your King shared the kingdom&#39;s plan and your alliance accepted it.</td></tr><tr><td><strong>Direct kingdom plan</strong></td><td>This kingdom has its own subscription.</td></tr><tr><td><strong>Free tier</strong></td><td>The automatic free fallback — nothing premium is active.</td></tr></tbody></table><p>If your label says <strong>Free tier</strong> and you expected premium, that&#39;s your clue: either no plan was ever activated, or a grant was offered but not yet accepted. See <a href="./accept-grant.html">Accept a Premium Offer</a>.</p><h2 id="why-this-matters" tabindex="-1">Why this matters <a class="header-anchor" href="#why-this-matters" aria-label="Permalink to &quot;Why this matters&quot;">​</a></h2><ul><li><strong>Leaders:</strong> if you&#39;re waiting on premium from your King, check your plan source. Until it reads <em>Accepted kingdom grant</em>, the offer hasn&#39;t taken effect — you may still need to <a href="./accept-grant.html">accept it</a>.</li><li><strong>Kings:</strong> offering a grant isn&#39;t the finish line. It only counts once the alliance accepts. See <a href="./kingdom-grants.html">Kingdom Grants</a>.</li></ul><h2 id="where-to-go-next" tabindex="-1">Where to go next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where to go next&quot;">​</a></h2><ul><li><a href="./kingdom-grants.html">Kingdom Grants</a> — how a King offers premium to alliances.</li><li><a href="./accept-grant.html">Accept a Premium Offer</a> — how a leader turns an offer into an active plan.</li><li><a href="./direct-alliance-subscription.html">Direct Alliance Subscriptions</a> — when an alliance has its own plan instead.</li></ul>`,20)])])}const g=e(i,[["render",o]]);export{u as __pageData,g as default};
